import { type KeyboardEvent, type TouchEvent } from "react";

interface SliderInputProps {
  id: string;
  label: string;
  value: number;
  min: number;
  max: number;
  step?: number;
  onChange: (val: number) => void;
  format?: (val: number) => string;
  testId?: string;
  helpText?: string;
}

function formatBound(value: number) {
  return Number.isInteger(value) ? value.toLocaleString() : value.toLocaleString(undefined, { maximumFractionDigits: 4 });
}

export default function SliderInput({
  id, label, value, min, max, step = 1, onChange, format, testId, helpText,
}: SliderInputProps) {
  const display = format ? format(value) : value.toLocaleString();
  const pct = Math.min(100, Math.max(0, ((value - min) / (max - min)) * 100));
  const isInvalid = Number.isNaN(value) || value < min || value > max;
  const rangeHint = `Enter ${label.toLowerCase()} between ${formatBound(min)} and ${formatBound(max)}.`;

  const decimals = step.toString().includes(".") ? step.toString().split(".")[1].length : 0;

  const valueFromTouch = (clientX: number, target: HTMLInputElement) => {
    const rect = target.getBoundingClientRect();
    if (rect.width <= 0) return value;
    const ratio = Math.min(1, Math.max(0, (clientX - rect.left) / rect.width));
    const rawValue = min + ratio * (max - min);
    const stepped = Math.round((rawValue - min) / step) * step + min;
    const clamped = Math.min(max, Math.max(min, stepped));
    return Number(clamped.toFixed(decimals));
  };

  const handleTouchSlider = (event: TouchEvent<HTMLInputElement>) => {
    event.preventDefault();
    event.stopPropagation();
    const touch = event.touches[0] || event.changedTouches[0];
    if (!touch) return;
    const next = valueFromTouch(touch.clientX, event.currentTarget);
    if (next !== value) onChange(next);
  };

  const preventInvalidNumberKeys = (event: KeyboardEvent<HTMLInputElement>) => {
    const allowedKeys = ["Backspace", "Delete", "Tab", "Escape", "Enter", "ArrowLeft", "ArrowRight", "ArrowUp", "ArrowDown", "Home", "End"];
    if (allowedKeys.includes(event.key) || event.ctrlKey || event.metaKey) return;
    const allowsDecimal = !Number.isInteger(step);
    const allowsNegative = min < 0;
    if (/^\d$/.test(event.key)) return;
    if (allowsDecimal && event.key === "." && !event.currentTarget.value.includes(".")) return;
    if (allowsNegative && event.key === "-" && event.currentTarget.selectionStart === 0 && !event.currentTarget.value.includes("-")) return;
    event.preventDefault();
  };

  return (
    <div className="space-y-2.5">
      <div className="flex items-center justify-between gap-3">
        <label htmlFor={`${id}-slider`} className="text-sm font-semibold text-foreground leading-none">
          {label}
        </label>
        <span className="text-sm font-bold text-primary bg-primary/8 border border-primary/20 px-2.5 py-1 rounded-lg whitespace-nowrap tabular-nums min-w-[3.5rem] text-center">
          {display}
        </span>
      </div>

      <input
        type="range"
        id={`${id}-slider`}
        min={min}
        max={max}
        step={step}
        value={Math.min(max, Math.max(min, value))}
        onChange={(e) => {
          const next = Number(e.target.value);
          onChange(next);
        }}
        onTouchStart={handleTouchSlider}
        onTouchMove={handleTouchSlider}
        onTouchEnd={handleTouchSlider}
        data-testid={testId ? `slider-${testId}` : undefined}
        className="pc-slider w-full h-11 rounded-full appearance-none cursor-pointer touch-none select-none"
        aria-valuetext={display}
        style={{
          background: `linear-gradient(to right, hsl(var(--primary)) ${pct}%, hsl(var(--muted)) ${pct}%) center / 100% 0.5rem no-repeat`,
          touchAction: "none",
        }}
      />

      <div className="flex flex-col sm:flex-row sm:items-center gap-2.5">
        <input
          type="number"
          inputMode="decimal"
          id={id}
          min={min}
          max={max}
          step={step}
          value={value}
          aria-invalid={isInvalid}
          aria-describedby={`${id}-hint`}
          onKeyDown={preventInvalidNumberKeys}
          onChange={(e) => {
            const v = Number(e.target.value);
            if (!isNaN(v)) onChange(v);
          }}
          onBlur={(e) => {
            const v = Number(e.target.value);
            onChange(Math.min(max, Math.max(min, isNaN(v) ? min : v)));
          }}
          data-testid={testId}
          className={`w-full sm:w-32 min-h-[44px] px-3 py-2 rounded-xl border bg-background text-foreground text-sm font-medium focus:outline-none focus:ring-2 transition-all tabular-nums ${
            isInvalid
              ? "border-red-400 focus:border-red-500 focus:ring-red-500/20"
              : "border-input focus:border-primary focus:ring-primary/30"
          }`}
        />
        <p id={`${id}-hint`} className={`text-xs leading-tight ${isInvalid ? "text-red-600 dark:text-red-400" : "text-muted-foreground"}`}>
          {isInvalid ? rangeHint : (helpText || rangeHint)}
        </p>
      </div>
    </div>
  );
}
